import React, { useEffect, useState } from 'react';

/* ═══════════════════════════════════════════════════════════════════════════
   TOAST SYSTEM
   ═══════════════════════════════════════════════════════════════════════════ */

const toastListeners = new Set();
let toastId = 0;

export function toast(msg, type = 'info') {
  const id = ++toastId;
  const item = { id, msg, type };
  toastListeners.forEach((fn) => fn(item));
}

export function ToastContainer() {
  const [items, setItems] = useState([]);

  useEffect(() => {
    const onToast = (t) => {
      setItems((prev) => [...prev, t]);
      setTimeout(() => {
        setItems((prev) => prev.filter((x) => x.id !== t.id));
      }, 4000);
    };
    toastListeners.add(onToast);
    return () => toastListeners.delete(onToast);
  }, []);

  const iconMap = {
    success: '✓',
    error: '✕',
    info: 'ℹ',
    warning: '⚠',
  };

  const colorMap = {
    success: { bg: 'var(--success)', accent: 'rgba(16, 185, 129, 0.1)' },
    error:   { bg: 'var(--danger)',  accent: 'rgba(239, 68, 68, 0.1)' },
    info:    { bg: 'var(--primary)', accent: 'rgba(30, 23, 96, 0.1)' },
    warning: { bg: 'var(--warning)', accent: 'rgba(255, 172, 12, 0.1)' },
  };

  return (
    <div
      style={{
        position: 'fixed',
        top: 16,
        right: 16,
        zIndex: 20000,
        display: 'flex',
        flexDirection: 'column',
        gap: 8,
        maxWidth: 400,
        pointerEvents: 'none',
      }}
    >
      {items.map((t) => {
        const c = colorMap[t.type] || colorMap.info;
        return (
          <div
            key={t.id}
            style={{
              animation: 'slideInRight 0.3s ease-out',
              background: 'var(--white)',
              color: 'var(--text-dark)',
              padding: '12px 16px',
              borderRadius: '10px',
              borderLeft: `3px solid ${c.bg}`,
              fontSize: 13,
              boxShadow: 'var(--shadow)',
              display: 'flex',
              alignItems: 'center',
              gap: 10,
              pointerEvents: 'auto',
              border: '1px solid var(--gray-200)',
            }}
          >
            <span
              style={{
                width: 26,
                height: 26,
                borderRadius: '50%',
                background: c.accent,
                color: c.bg,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontWeight: 700,
                fontSize: 12,
                flexShrink: 0,
              }}
            >
              {iconMap[t.type] || iconMap.info}
            </span>
            <span style={{ flex: 1, lineHeight: 1.4, fontWeight: 500 }}>{t.msg}</span>
            <button
              onClick={() => setItems((prev) => prev.filter((x) => x.id !== t.id))}
              style={{
                background: 'none',
                border: 'none',
                color: 'var(--gray-500)',
                cursor: 'pointer',
                fontSize: 16,
                lineHeight: 1,
                padding: 4,
                flexShrink: 0,
                borderRadius: '4px',
                transition: 'all 0.15s',
              }}
              onMouseEnter={(e) => (e.currentTarget.style.background = 'var(--gray-100)')}
              onMouseLeave={(e) => (e.currentTarget.style.background = 'none')}
            >
              ×
            </button>
          </div>
        );
      })}
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   SPINNER
   ═══════════════════════════════════════════════════════════════════════════ */

export function Spinner({ size = 20, color = 'var(--primary)' }) {
  return (
    <span
      style={{
        display: 'inline-block',
        width: size,
        height: size,
        border: `2px solid ${color}20`,
        borderTopColor: color,
        borderRadius: '50%',
        animation: 'spin 0.6s linear infinite',
        verticalAlign: 'middle',
      }}
    />
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   BUTTON
   ═══════════════════════════════════════════════════════════════════════════ */

const btnBase = {
  border: 'none',
  borderRadius: '6px',
  fontFamily: 'var(--font-body)',
  fontWeight: 500,
  cursor: 'pointer',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  gap: 6,
  transition: 'all 0.15s ease',
  outline: 'none',
  letterSpacing: '-0.01em',
  position: 'relative',
  whiteSpace: 'nowrap',
};

const variants = {
  primary: {
    background: 'var(--primary)',
    color: 'var(--white)',
    boxShadow: '0 1px 3px rgba(27, 110, 243, 0.25)',
  },
  secondary: {
    background: 'var(--white)',
    color: 'var(--text-dark)',
    border: '1px solid var(--border-color)',
    boxShadow: 'var(--shadow)',
  },
  ghost: {
    background: 'transparent',
    color: 'var(--text-light)',
  },
  danger: {
    background: 'var(--danger)',
    color: 'var(--white)',
    boxShadow: '0 1px 3px rgba(220, 38, 38, 0.25)',
  },
  success: {
    background: 'var(--success)',
    color: 'var(--white)',
    boxShadow: '0 1px 3px rgba(5, 150, 105, 0.25)',
  },
  outline: {
    background: 'transparent',
    color: 'var(--primary)',
    border: '1px solid var(--primary)',
  },
};

const sizes = {
  xs: { padding: '4px 10px', fontSize: 12 },
  sm: { padding: '6px 14px', fontSize: 13 },
  md: { padding: '8px 16px', fontSize: 13 },
  lg: { padding: '10px 22px', fontSize: 14 },
};

export function Btn({
  variant = 'primary',
  size = 'md',
  loading,
  disabled,
  onClick,
  type = 'button',
  style,
  children,
  ...rest
}) {
  const dim = disabled || loading;
  return (
    <button
      type={type}
      onClick={dim ? undefined : onClick}
      style={{
        ...btnBase,
        ...variants[variant],
        ...sizes[size],
        opacity: dim ? 0.55 : 1,
        cursor: dim ? 'not-allowed' : 'pointer',
        ...style,
      }}
      disabled={dim}
      onMouseEnter={(e) => {
        if (!dim) {
          e.currentTarget.style.transform = 'translateY(-1px)';
          e.currentTarget.style.filter = 'brightness(1.05)';
        }
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.filter = 'brightness(1)';
      }}
      {...rest}
    >
      {loading && <Spinner size={14} color="currentColor" />}
      {children}
    </button>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   CARD
   ═══════════════════════════════════════════════════════════════════════════ */

export function Card({ children, style, hover, ...rest }) {
  const [hovered, setHovered] = useState(false);
  return (
    <div
      onMouseEnter={() => hover && setHovered(true)}
      onMouseLeave={() => hover && setHovered(false)}
      style={{
        background: 'var(--white)',
        border: '1px solid var(--border-color)',
        borderRadius: '10px',
        padding: 24,
        boxShadow: hovered ? '0 10px 15px rgba(0, 0, 0, 0.1)' : 'var(--shadow)',
        transition: 'box-shadow 0.25s ease, transform 0.25s ease',
        transform: hovered ? 'translateY(-2px)' : 'none',
        ...style,
      }}
      {...rest}
    >
      {children}
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   INPUT
   ═══════════════════════════════════════════════════════════════════════════ */

export function Input({ label, error, style, ...props }) {
  return (
    <label style={{ display: 'block', marginBottom: 14, ...style }}>
      {label && (
        <span
          style={{
            display: 'block',
            fontSize: 13,
            fontWeight: 500,
            color: 'var(--text-light)',
            marginBottom: 5,
            letterSpacing: '-0.01em',
          }}
        >
          {label}
        </span>
      )}
      <input
        {...props}
        style={{
          width: '100%',
          padding: '8px 12px',
          borderRadius: '6px',
          border: `1px solid ${error ? 'var(--danger)' : 'var(--border-color)'}`,
          fontFamily: 'var(--font-body)',
          fontSize: 13,
          outline: 'none',
          background: 'var(--white)',
          color: 'var(--text-dark)',
          transition: 'border-color 0.15s ease, box-shadow 0.15s ease',
          letterSpacing: '-0.01em',
        }}
        onFocus={(e) => {
          e.target.style.borderColor = 'var(--primary)';
          e.target.style.boxShadow = '0 0 0 3px rgba(30, 23, 96, 0.1)';
          props.onFocus?.(e);
        }}
        onBlur={(e) => {
          e.target.style.borderColor = error ? 'var(--danger)' : 'var(--border-color)';
          e.target.style.boxShadow = 'none';
          props.onBlur?.(e);
        }}
      />
      {error && (
        <span style={{ color: 'var(--danger)', fontSize: 12, marginTop: 4, display: 'block' }}>
          {error}
        </span>
      )}
    </label>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   SELECT
   ═══════════════════════════════════════════════════════════════════════════ */

export function Select({ label, error, children, style, ...props }) {
  return (
    <label style={{ display: 'block', marginBottom: 14, ...style }}>
      {label && (
        <span
          style={{
            display: 'block',
            fontSize: 13,
            fontWeight: 500,
            color: 'var(--text-light)',
            marginBottom: 5,
            letterSpacing: '-0.01em',
          }}
        >
          {label}
        </span>
      )}
      <select
        {...props}
        style={{
          width: '100%',
          padding: '8px 12px',
          borderRadius: '6px',
          border: `1px solid ${error ? 'var(--danger)' : 'var(--border-color)'}`,
          fontFamily: 'var(--font-body)',
          fontSize: 13,
          background: 'var(--white)',
          color: 'var(--text-dark)',
          cursor: 'pointer',
          outline: 'none',
          transition: 'border-color 0.15s ease, box-shadow 0.15s ease',
          appearance: 'none',
          backgroundImage: `url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' fill='none' viewBox='0 0 20 20'%3e%3cpath stroke='%236b7280' stroke-linecap='round' stroke-linejoin='round' stroke-width='1.5' d='M6 8l4 4 4-4'/%3e%3c/svg%3e")`,
          backgroundPosition: 'right 8px center',
          backgroundRepeat: 'no-repeat',
          backgroundSize: '18px',
          paddingRight: 32,
        }}
      >
        {children}
      </select>
      {error && (
        <span style={{ color: 'var(--danger)', fontSize: 12, marginTop: 4, display: 'block' }}>
          {error}
        </span>
      )}
    </label>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   TEXTAREA
   ═══════════════════════════════════════════════════════════════════════════ */

export function Textarea({ label, error, style, ...props }) {
  return (
    <label style={{ display: 'block', marginBottom: 14, ...style }}>
      {label && (
        <span
          style={{
            display: 'block',
            fontSize: 13,
            fontWeight: 500,
            color: 'var(--text-light)',
            marginBottom: 5,
          }}
        >
          {label}
        </span>
      )}
      <textarea
        {...props}
        style={{
          width: '100%',
          padding: '8px 12px',
          borderRadius: '6px',
          border: `1px solid ${error ? 'var(--danger)' : 'var(--border-color)'}`,
          fontFamily: 'var(--font-body)',
          fontSize: 13,
          outline: 'none',
          background: 'var(--white)',
          color: 'var(--text-dark)',
          resize: 'vertical',
          minHeight: 80,
          transition: 'border-color 0.15s ease, box-shadow 0.15s ease',
          lineHeight: 1.5,
        }}
        onFocus={(e) => {
          e.target.style.borderColor = 'var(--primary)';
          e.target.style.boxShadow = '0 0 0 3px rgba(30, 23, 96, 0.1)';
          props.onFocus?.(e);
        }}
        onBlur={(e) => {
          e.target.style.borderColor = error ? 'var(--danger)' : 'var(--border-color)';
          e.target.style.boxShadow = 'none';
          props.onBlur?.(e);
        }}
      />
      {error && (
        <span style={{ color: 'var(--danger)', fontSize: 12, marginTop: 4, display: 'block' }}>
          {error}
        </span>
      )}
    </label>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   MODAL
   ═══════════════════════════════════════════════════════════════════════════ */

export function Modal({ open, onClose, title, children, width = 500 }) {
  useEffect(() => {
    if (!open) return;
    const onKey = (e) => e.key === 'Escape' && onClose?.();
    document.body.style.overflow = 'hidden';
    window.addEventListener('keydown', onKey);
    return () => {
      document.body.style.overflow = '';
      window.removeEventListener('keydown', onKey);
    };
  }, [open, onClose]);

  if (!open) return null;

  return (
    <div
      role="presentation"
      style={{
        position: 'fixed',
        inset: 0,
        background: 'rgba(0, 0, 0, 0.45)',
        backdropFilter: 'blur(6px)',
        WebkitBackdropFilter: 'blur(6px)',
        zIndex: 10000,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 24,
        animation: 'fadeIn 0.15s ease-out',
      }}
      onClick={onClose}
    >
      <div
        role="dialog"
        onClick={(e) => e.stopPropagation()}
        style={{
          animation: 'fadeInScale 0.25s ease-out',
          background: 'var(--white)',
          borderRadius: '16px',
          width: '100%',
          maxWidth: width,
          maxHeight: '90vh',
          overflow: 'auto',
          boxShadow: 'var(--shadow)',
          border: '1px solid var(--gray-200)',
        }}
      >
        <div
          style={{
            padding: '16px 20px',
            borderBottom: '1px solid var(--border-color)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            position: 'sticky',
            top: 0,
            background: 'var(--white)',
            zIndex: 1,
            borderRadius: '16px 16px 0 0',
          }}
        >
          <h2 style={{ fontSize: 16, fontWeight: 600 }}>{title}</h2>
          <button
            type="button"
            onClick={onClose}
            style={{
              border: 'none',
              background: 'transparent',
              width: 30,
              height: 30,
              borderRadius: '6px',
              fontSize: 18,
              cursor: 'pointer',
              color: 'var(--gray-500)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              transition: 'all 0.15s',
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.background = 'rgba(239, 68, 68, 0.1)';
              e.currentTarget.style.color = 'var(--danger)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.background = 'transparent';
              e.currentTarget.style.color = 'var(--gray-500)';
            }}
          >
            ×
          </button>
        </div>
        <div style={{ padding: 20 }}>{children}</div>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
   TABLE
   ═══════════════════════════════════════════════════════════════════════════ */

export function Table({ cols, rows, loading, emptyMsg = 'No data found' }) {
  if (loading) {
    return (
      <div style={{ padding: 48, textAlign: 'center' }}>
        <Spinner size={28} />
        <p style={{ marginTop: 12, color: 'var(--gray-500)', fontSize: 13 }}>Loading data...</p>
      </div>
    );
  }
  if (!rows?.length) {
    return (
      <div
        style={{
          padding: '56px 24px',
          textAlign: 'center',
          color: 'var(--gray-500)',
          fontSize: 13,
        }}
      >
        <div style={{ fontSize: 36, marginBottom: 8, opacity: 0.35 }}>📋</div>
        <p style={{ fontWeight: 500, color: 'var(--text-light)', marginBottom: 2 }}>{emptyMsg}</p>
        <p style={{ fontSize: 12, color: 'var(--gray-500)' }}>Records will appear here when available</p>
      </div>
    );
  }
  return (
    <div style={{ overflowX: 'auto' }}>
      <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
        <thead>
          <tr style={{ background: 'var(--gray-100)' }}>
            {cols.map((c) => (
              <th
                key={c.key}
                style={{
                  textAlign: 'left',
                  padding: '10px 16px',
                  fontSize: 11,
                  textTransform: 'uppercase',
                  letterSpacing: '0.06em',
                  fontWeight: 600,
                  color: 'var(--gray-500)',
                  borderBottom: '1px solid var(--border-color)',
                  whiteSpace: 'nowrap',
                }}
              >
                {c.label}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {rows.map((row, i) => (
            <tr
              key={row.key ?? row.id ?? i}
              style={{
                background: 'var(--white)',
                transition: 'background 0.1s',
              }}
              onMouseEnter={(e) => (e.currentTarget.style.background = 'var(--gray-100)')}
              onMouseLeave={(e) => (e.currentTarget.style.background = 'var(--white)')}
            >
              {cols.map((c) => (
                <td
                  key={c.key}
                  style={{
                    padding: '10px 16px',
                    borderBottom: '1px solid var(--gray-200)',
                    verticalAlign: 'middle',
                    color: 'var(--text-dark)',
                    lineHeight: 1.5,
                  }}
                >
                  {c.render ? c.render(row) : row[c.key]}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════════
