            flexShrink: 0,
            transition: 'transform 0.2s ease',
          }}
        >
          {icon}
        </div>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div
            style={{
              fontSize: 26,
              fontWeight: 700,
              color: 'var(--text-dark)',
